const MANAGE_CENTER_SECTION_TOKENS: ReadonlySet<ManageCenterSection> = new Set<ManageCenterSection>([
  "versionHistory",
  "publishPromote",
  "adminConsole",
  "recovery",
  "preferences",
  "sharing",
  "fileOptions",
  "importExport",
  "fileReferences",
  "authProfiles",
  "pluginManager",
  "helpDiagnostics",
  "database",
  "security",
  "valueLists",
  "layouts",
  "scripts",
  "externalDataSources",
  "containers",
  "customFunctions",
  "customMenus",
  "themes"
]);

const MANAGE_CENTER_DIALOG_SECTIONS: ReadonlySet<ManageCenterSection> = new Set<ManageCenterSection>([
  "database",
  "security",
  "valueLists",
  "layouts",
  "scripts",
  "externalDataSources",
  "containers",
  "customFunctions",
  "customMenus",
  "themes"
]);

function shouldOpenManageSectionAsDialog(section: ManageCenterSection): boolean {
  return MANAGE_CENTER_DIALOG_SECTIONS.has(section);
}

function parseManageCenterSectionToken(token: string | undefined): ManageCenterSection | null {
  const normalized = String(token ?? "").trim();
  if (!normalized) {
    return null;
  }
  if (MANAGE_CENTER_SECTION_TOKENS.has(normalized as ManageCenterSection)) {
    return normalized as ManageCenterSection;
  }
  return null;
}

