function normalizeTooltipText(raw: string): string {
  return raw.replace(/\s+/g, " ").replace(/^[✓✔]\s*/, "").trim();
}

function tooltipFromLabel(control: HTMLElement): string {
  const label = control.closest("label");
  if (!label) {
    return "";
  }
  const clone = label.cloneNode(true) as HTMLElement;
  clone.querySelectorAll("button, input, select, textarea, datalist").forEach((node) => node.remove());
  return normalizeTooltipText(clone.textContent ?? "");
}

function inferTooltip(control: HTMLElement): string {
  const ariaLabel = normalizeTooltipText(control.getAttribute("aria-label") ?? "");
  if (ariaLabel) {
    return ariaLabel;
  }
  if (control instanceof HTMLInputElement || control instanceof HTMLTextAreaElement) {
    const placeholder = normalizeTooltipText(control.placeholder ?? "");
    if (placeholder) {
      return placeholder;
    }
  }
  const labelText = tooltipFromLabel(control);
  if (labelText) {
    return labelText;
  }
  return normalizeTooltipText(control.textContent ?? "");
}

function applyMissingTooltips(root: HTMLElement, enabled: boolean): void {
  const controls = root.querySelectorAll<HTMLElement>(
    "button, a, select, input:not([type='hidden']), textarea"
  );
  controls.forEach((control) => {
    const wasAutoAssigned = control.getAttribute("data-auto-tooltip") === "true";
    if (!enabled) {
      if (wasAutoAssigned) {
        control.removeAttribute("title");
        control.removeAttribute("data-auto-tooltip");
      }
      return;
    }
    if (control.hasAttribute("title") && !wasAutoAssigned) {
      return;
    }
    const tooltip = inferTooltip(control);
    if (!tooltip) {
      return;
    }
    control.setAttribute("title", tooltip);
    control.setAttribute("data-auto-tooltip", "true");
  });
}

function updateComponent(
  layout: LayoutDefinition,
  componentId: string,
  updater: (component: LayoutComponent) => LayoutComponent
): LayoutDefinition {
  return {
    ...layout,
    components: layout.components.map((component) =>
      component.id === componentId ? updater(component) : component
    )
  };
}

function cloneComponentForClipboard(component: LayoutComponent): LayoutComponent {
  return {
    ...component,
    binding: component.binding ? { ...component.binding } : undefined,
    props: { ...component.props },
    events: component.events
      ? {
          ...component.events,
          onClick: component.events.onClick ? { ...component.events.onClick } : undefined
        }
      : undefined
  };
}

function createFieldComponentWithLabel(
  fieldName: string,
  preferences?: FieldDragPreferences,
  tableOccurrence?: string
): LayoutComponent {
  const placement = preferences?.placement ?? "side-by-side";
  const controlType = preferences?.controlType ?? "text";
  const labelPlacement: NonNullable<LayoutComponent["props"]["labelPlacement"]> =
    placement === "stacked" ? "top" : placement === "field-only" ? "none" : "left";
  const shouldShowLabel = labelPlacement !== "none";

  const component = createComponent("field");
  component.binding = {
    ...component.binding,
    field: fieldName,
    ...(tableOccurrence ? { tableOccurrence } : {})
  };
  component.props = {
    ...component.props,
    label: shouldShowLabel ? fieldName : "",
    placeholder: fieldName,
    controlType,
    labelPlacement
  };
  component.position = {
    ...component.position,
    width: placement === "field-only" ? 260 : 360,
    height: placement === "stacked" ? 64 : 42
  };
  return component;
}

function normalizeFieldCatalog(fields: Array<FieldCatalogEntry | string>): FieldCatalogEntry[] {
  const normalizedByName = new Map<string, FieldCatalogEntry>();
  for (const fieldEntry of fields) {
    if (typeof fieldEntry === "string") {
      const name = fieldEntry.trim();
      if (!name) {
        continue;
      }
      if (!normalizedByName.has(name)) {
        normalizedByName.set(name, { name, type: "Text" });
      }
      continue;
    }

    const name = String(fieldEntry.name ?? "").trim();
    if (!name) {
      continue;
    }
    const type = String(fieldEntry.type ?? "Text").trim() || "Text";
    normalizedByName.set(name, {
      name,
      type
    });
  }

  return [...normalizedByName.values()].sort((a, b) => a.name.localeCompare(b.name));
}

function normalizeRelationshipGraphTables(
  tables: RelationshipGraphTable[] | undefined
): RelationshipGraphTable[] {
  if (!Array.isArray(tables) || tables.length === 0) {
    return [];
  }
  const normalized = new Map<string, RelationshipGraphTable>();
  for (let index = 0; index < tables.length; index += 1) {
    const table = tables[index];
    const id = String(table?.id ?? "").trim();
    const name = String(table?.name ?? "").trim();
    const key = id || `name:${name.toLowerCase()}`;
    if (!key || !name) {
      continue;
    }
    const creationIndex =
      Number.isFinite(Number(table?.creationIndex)) && Number(table?.creationIndex) > 0
        ? Number(table.creationIndex)
        : index + 1;
    normalized.set(key, {
      id: id || `${creationIndex}`,
      name,
      source: String(table?.source ?? "FileMaker").trim() || "FileMaker",
      comment: String(table?.comment ?? "").trim(),
      creationIndex
    });
  }
  return [...normalized.values()];
}

function normalizeRelationshipOperator(operator: string): string {
  const normalized = operator.trim().toLowerCase();
  if (!normalized || normalized === "equal" || normalized === "equals") {
    return "=";
  }
  if (normalized === "notequal" || normalized === "not equal") {
    return "<>";
  }
  if (normalized === "greaterthan") {
    return ">";
  }
  if (normalized === "greaterthanorequal") {
    return ">=";
  }
  if (normalized === "lessthan") {
    return "<";
  }
  if (normalized === "lessthanorequal") {
    return "<=";
  }
  return operator.trim();
}

const MANAGE_DATABASE_RELATIONSHIP_OPERATORS = ["=", "<>", ">", ">=", "<", "<="] as const;

function toManageDatabaseRelationshipOperatorLabel(operator: string): string {
  const normalized = normalizeRelationshipOperator(operator);
  if (MANAGE_DATABASE_RELATIONSHIP_OPERATORS.includes(normalized as (typeof MANAGE_DATABASE_RELATIONSHIP_OPERATORS)[number])) {
    return normalized;
  }
  return "=";
}

