function snapshotObjectStyleProps(component: LayoutComponent): Partial<LayoutComponent["props"]> {
  const snapshot: Partial<LayoutComponent["props"]> = {};
  const snapshotRecord = snapshot as Record<string, unknown>;
  for (const key of styleClipboardKeys) {
    const value = component.props[key];
    if (typeof value === "undefined") {
      continue;
    }
    if (Array.isArray(value)) {
      snapshotRecord[key] = [...value];
      continue;
    }
    snapshotRecord[key] = value;
  }
  return snapshot;
}

type EditableTarget = HTMLInputElement | HTMLTextAreaElement | HTMLElement;

function resolveActiveEditableTarget(): EditableTarget | null {
  if (typeof document === "undefined") {
    return null;
  }
  const active = document.activeElement;
  if (!(active instanceof HTMLElement)) {
    return null;
  }
  if (active instanceof HTMLInputElement) {
    const editableTypes = new Set([
      "",
      "text",
      "search",
      "url",
      "tel",
      "email",
      "password",
      "number"
    ]);
    if (active.readOnly || active.disabled || !editableTypes.has((active.type ?? "").toLowerCase())) {
      return null;
    }
    return active;
  }
  if (active instanceof HTMLTextAreaElement) {
    if (active.readOnly || active.disabled) {
      return null;
    }
    return active;
  }
  if (active.isContentEditable) {
    return active;
  }
  return null;
}

function dispatchInputEvent(target: EditableTarget): void {
  target.dispatchEvent(new Event("input", { bubbles: true }));
  target.dispatchEvent(new Event("change", { bubbles: true }));
}

function insertPlainTextIntoTarget(target: EditableTarget, text: string): boolean {
  if (target instanceof HTMLInputElement || target instanceof HTMLTextAreaElement) {
    const start = target.selectionStart ?? target.value.length;
    const end = target.selectionEnd ?? start;
    target.setRangeText(text, start, end, "end");
    dispatchInputEvent(target);
    return true;
  }
  if (typeof document !== "undefined" && typeof document.execCommand === "function") {
    target.focus();
    const inserted = document.execCommand("insertText", false, text);
    if (inserted) {
      dispatchInputEvent(target);
      return true;
    }
  }
  target.textContent = `${target.textContent ?? ""}${text}`;
  dispatchInputEvent(target);
  return true;
}

function clearEditableTarget(target: EditableTarget): boolean {
  if (target instanceof HTMLInputElement || target instanceof HTMLTextAreaElement) {
    target.value = "";
    dispatchInputEvent(target);
    return true;
  }
  target.textContent = "";
  dispatchInputEvent(target);
  return true;
}

function layoutPreviewClasses(component: LayoutComponent): string {
  const classes = [
    `runtime-item-type-${component.type}`,
    `runtime-style-${styleToken(component.props.styleName)}`,
    `runtime-variant-${component.props.variant ?? "primary"}`
  ];
  if (component.type === "button") {
    classes.push(`runtime-button-mode-${component.props.buttonMode ?? "standard"}`);
  }
  if (component.type === "panel") {
    classes.push(`runtime-panel-type-${component.props.panelType ?? "tab"}`);
  }
  if (isUniversalTouchTheme(component.props.styleTheme)) {
    classes.push("runtime-theme-universal-touch");
  }
  return classes.join(" ");
}

function detectShortcutDocsPlatform(): ShortcutDocsPlatform {
  if (typeof navigator === "undefined") {
    return "unknown";
  }
  const navigatorWithUAData = navigator as Navigator & { userAgentData?: { platform?: string } };
  const platform = navigatorWithUAData.userAgentData?.platform || navigator.platform || "";
  const userAgent = navigator.userAgent || "";
  const touchPoints = Number(navigator.maxTouchPoints || 0);
  const hasTouch = touchPoints > 0;
  const isIPhone = /iPhone|iPod/i.test(userAgent);
  const isIPad = /iPad/i.test(userAgent) || (hasTouch && /Mac/i.test(platform));
  if (isIPhone || isIPad || /Android|Mobile|Tablet/i.test(userAgent)) {
    return "mobile";
  }
  if (/Win/i.test(platform) || /Windows/i.test(userAgent)) {
    return "windows";
  }
  if (/Mac|Intel Mac/i.test(platform) || /Macintosh|Mac OS X/i.test(userAgent)) {
    return "mac";
  }
  return "unknown";
}

function keyboardShortcutsDocsUrl(platform: ShortcutDocsPlatform): string {
  if (platform === "windows") {
    return HELP_URL_SHORTCUTS_WINDOWS;
  }
  return HELP_URL_SHORTCUTS_MAC;
}

function filterHelpMenuEntries(searchTerm: string): HelpMenuEntry[] {
  const normalized = searchTerm.trim().toLowerCase();
  if (!normalized) {
    return helpMenuEntries;
  }
  const raw = helpMenuEntries.filter((entry) => {
    if (entry.kind === "divider") {
      return true;
    }
    const text = `${entry.label} ${entry.keywords}`.toLowerCase();
    return text.includes(normalized);
  });
  const cleaned: HelpMenuEntry[] = [];
  for (let index = 0; index < raw.length; index += 1) {
    const entry = raw[index];
    if (entry.kind === "divider") {
      const hasPreviousAction = cleaned.length > 0 && cleaned[cleaned.length - 1]?.kind === "action";
      if (!hasPreviousAction) {
        continue;
      }
      const hasNextAction = raw.slice(index + 1).some((candidate) => candidate.kind === "action");
      if (!hasNextAction) {
        continue;
      }
    }
    cleaned.push(entry);
  }
  while (cleaned.length > 0 && cleaned[0]?.kind === "divider") {
    cleaned.shift();
  }
  while (cleaned.length > 0 && cleaned[cleaned.length - 1]?.kind === "divider") {
    cleaned.pop();
  }
  return cleaned;
}

function normalizeWorkspaceToken(value: string | undefined): string {
  const cleaned = String(value ?? "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_-]+/g, "-")
    .replace(/^-+|-+$/g, "");
  return cleaned || "default";
}

function withWorkspaceQuery(pathname: string, workspaceId: string): string {
  const separator = pathname.includes("?") ? "&" : "?";
  return `${pathname}${separator}workspace=${encodeURIComponent(workspaceId)}`;
}

function downloadClientFile(filename: string, payload: string, contentType: string): void {
  const blob = new Blob([payload], { type: contentType });
  const downloadUrl = URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = downloadUrl;
  anchor.download = filename;
  document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
  URL.revokeObjectURL(downloadUrl);
}

function escapeCsvCell(value: unknown): string {
  const text = String(value ?? "");
  if (!/[",\n\r]/.test(text)) {
    return text;
  }
  return `"${text.replace(/"/g, "\"\"")}"`;
}

function parseCsvText(input: string): {
  headers: string[];
  rows: Array<Record<string, string>>;
} {
  const rows: string[][] = [];
  let currentCell = "";
  let currentRow: string[] = [];
  let inQuotes = false;
  for (let index = 0; index < input.length; index += 1) {
    const character = input[index];
    const nextCharacter = input[index + 1];
    if (character === "\"") {
      if (inQuotes && nextCharacter === "\"") {
        currentCell += "\"";
        index += 1;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }
    if (!inQuotes && character === ",") {
      currentRow.push(currentCell);
      currentCell = "";
      continue;
    }
    if (!inQuotes && (character === "\n" || character === "\r")) {
      if (character === "\r" && nextCharacter === "\n") {
        index += 1;
      }
      currentRow.push(currentCell);
      rows.push(currentRow);
      currentRow = [];
      currentCell = "";
      continue;
    }
    currentCell += character;
  }
  currentRow.push(currentCell);
  if (currentRow.some((value) => value.length > 0) || rows.length === 0) {
    rows.push(currentRow);
  }

  const rawHeaders = rows[0] ?? [];
  const headers = rawHeaders
    .map((header, headerIndex) => header.trim() || `Column${headerIndex + 1}`)
    .filter((header, headerIndex, values) => values.indexOf(header) === headerIndex);
  const dataRows = rows.slice(1).filter((row) => row.some((value) => String(value).trim().length > 0));
  const mappedRows = dataRows.map((row) => {
    const mapped: Record<string, string> = {};
    headers.forEach((header, headerIndex) => {
      mapped[header] = String(row[headerIndex] ?? "");
    });
    return mapped;
  });
  return { headers, rows: mappedRows };
}

function appLayerConfigFingerprint(config: AppLayerWorkspaceConfigPayload | null | undefined): string {
  if (!config) {
    return "";
  }
  return JSON.stringify({
    externalDataSources: config.externalDataSources,
    customFunctions: config.customFunctions,
    themes: config.themes,
    securityRoles: config.securityRoles,
    containerSettings: config.containerSettings,
    preferences: config.preferences,
    fileOptions: config.fileOptions,
    sharing: config.sharing,
    fileReferences: config.fileReferences,
    authProfiles: config.authProfiles,
    pluginPreferences: config.pluginPreferences
  });
}

function manageValueListsFingerprint(rows: ManageValueListRow[]): string {
  return JSON.stringify(
    rows.map((entry) => ({
      id: String(entry.id ?? "").trim(),
      name: String(entry.name ?? "").trim(),
      source: String(entry.source ?? "").trim(),
      sourceFields: Array.isArray(entry.sourceFields)
        ? entry.sourceFields.map((fieldName) => String(fieldName ?? "").trim()).filter((fieldName) => fieldName.length > 0)
        : [],
      values: Array.isArray(entry.values)
        ? entry.values.map((value) => String(value ?? "").trim()).filter((value) => value.length > 0)
        : []
    }))
  );
}

function parseValueListMultiline(value: string): string[] {
  return value
    .split(/\r?\n/)
    .map((entry) => entry.trim())
    .filter((entry) => entry.length > 0);
}

function uniqueValueListName(existingNames: string[], baseName: string): string {
  const normalizedExisting = new Set(existingNames.map((entry) => entry.trim().toLowerCase()).filter((entry) => entry.length > 0));
  const cleanBase = baseName.trim() || "New Value List";
  if (!normalizedExisting.has(cleanBase.toLowerCase())) {
    return cleanBase;
  }
  let counter = 2;
  while (normalizedExisting.has(`${cleanBase} ${counter}`.toLowerCase())) {
    counter += 1;
  }
  return `${cleanBase} ${counter}`;
}

function dedupeCaseInsensitiveStrings(values: string[]): string[] {
  const deduped: string[] = [];
  const seen = new Set<string>();
  for (const value of values) {
    const normalized = String(value ?? "").trim();
    if (!normalized) {
      continue;
    }
    const key = normalized.toLowerCase();
    if (seen.has(key)) {
      continue;
    }
    seen.add(key);
    deduped.push(normalized);
  }
  return deduped;
}

function appLayerOverridesEqual(
  left: AppLayerCapabilityOverrideMap,
  right: AppLayerCapabilityOverrideMap
): boolean {
  const leftEntries = Object.entries(left).sort(([leftKey], [rightKey]) =>
    leftKey.localeCompare(rightKey, undefined, { sensitivity: "base" })
  );
  const rightEntries = Object.entries(right).sort(([leftKey], [rightKey]) =>
    leftKey.localeCompare(rightKey, undefined, { sensitivity: "base" })
  );
  if (leftEntries.length !== rightEntries.length) {
    return false;
  }
  for (let index = 0; index < leftEntries.length; index += 1) {
    const [leftKey, leftValue] = leftEntries[index] ?? ["", false];
    const [rightKey, rightValue] = rightEntries[index] ?? ["", false];
    if (leftKey !== rightKey || leftValue !== rightValue) {
      return false;
    }
  }
  return true;
}

