      const raw = window.localStorage.getItem("fmweb-app-layer-capability-overrides");
      if (!raw) {
        return;
      }
      const parsed = JSON.parse(raw) as Record<string, unknown>;
      const next: AppLayerCapabilityOverrideMap = {};
      for (const key of Object.keys(parsed)) {
        if (!appLayerCapabilityByKey.has(key as AppLayerCapabilityKey)) {
          continue;
        }
        const token = parsed[key];
        if (typeof token === "boolean") {
          next[key as AppLayerCapabilityKey] = token;
        }
      }
      setAppLayerCapabilityOverrides((previous) =>
        appLayerOverridesEqual(previous, next) ? previous : next
      );
