  const normalizeCustomMenuPayload = useCallback((payload: CustomMenuConfigPayload): CustomMenuConfigPayload => {
    const fallbackMenus = customMenuKeyOptions.map((entry, index) => ({
      id: `menu-${entry.key}`,
      name: entry.label,
      displayTitle: entry.label,
      menuKey: entry.key,
      creationOrder: index + 1,
      locked: true
    }));
    const rawMenus = Array.isArray(payload.customMenus) ? payload.customMenus : [];
    const customMenus: CustomMenuDefinition[] = rawMenus.length > 0
      ? rawMenus
          .map((entry, index) => {
            const normalizedId = String(entry.id ?? "").trim() || `menu-${index + 1}`;
            const keyCandidate = String(entry.menuKey ?? "").trim() as CustomMenuKey;
            const matchedKey =
              customMenuKeyOptions.find((option) => option.key === keyCandidate)?.key ?? customMenuKeyOptions[0].key;
            const fallbackLabel = customMenuKeyOptions.find((option) => option.key === matchedKey)?.label ?? "Menu";
            const normalizedName = String(entry.name ?? "").trim() || `Menu ${index + 1}`;
            return {
              id: normalizedId,
              name: normalizedName,
              displayTitle: String(entry.displayTitle ?? "").trim() || normalizedName || fallbackLabel,
              menuKey: matchedKey,
              comment: String(entry.comment ?? "").trim() || undefined,
              creationOrder: index + 1,
              locked: Boolean(entry.locked)
            };
          })
          .filter((entry, index, array) => array.findIndex((candidate) => candidate.id === entry.id) === index)
      : fallbackMenus;

    const menuIds = new Set(customMenus.map((entry) => entry.id));
    const rawSets = Array.isArray(payload.menuSets) ? payload.menuSets : [];
    const menuSets: CustomMenuSetDefinition[] = rawSets.length > 0
      ? rawSets
          .map((entry, index) => {
            const normalizedId = String(entry.id ?? "").trim() || `menu-set-${index + 1}`;
            const normalizedMenuIds = Array.isArray(entry.menuIds)
              ? [...new Set(entry.menuIds.map((menuId) => String(menuId ?? "").trim()).filter((menuId) => menuIds.has(menuId)))]
              : [];
            return {
              id: normalizedId,
              name: String(entry.name ?? "").trim() || `Menu Set ${index + 1}`,
              menuIds: normalizedMenuIds.length > 0 ? normalizedMenuIds : customMenus.map((menu) => menu.id),
              comment: String(entry.comment ?? "").trim() || undefined,
              creationOrder: index + 1,
              locked: Boolean(entry.locked)
            };
          })
          .filter((entry, index, array) => array.findIndex((candidate) => candidate.id === entry.id) === index)
      : [
          {
            id: "standard-filemaker-menus",
            name: "[Standard FileMaker Menus]",
            menuIds: customMenus.map((entry) => entry.id),
            creationOrder: 1,
            locked: true
          }
        ];

    const defaultMenuSetId =
      menuSets.find((entry) => entry.id === payload.defaultMenuSetId)?.id ?? menuSets[0]?.id ?? "";

    return {
      customMenus,
      menuSets,
      defaultMenuSetId
    };
  }, []);

  const applyCustomMenuDraft = useCallback((payload: CustomMenuConfigPayload) => {
    const normalized = normalizeCustomMenuPayload(payload);
    setCustomMenusDraft(normalized.customMenus);
    setCustomMenuSetsDraft(normalized.menuSets);
    setCustomMenuDefaultSetDraft(normalized.defaultMenuSetId);
    setCustomMenusSelectedId(normalized.customMenus[0]?.id ?? "");
    setCustomMenuSetsSelectedId(normalized.menuSets[0]?.id ?? "");
  }, [normalizeCustomMenuPayload]);

