  const saveLayoutCopyAsXml = useCallback(() => {
    if (!layout) {
      setStatus("No layout loaded");
      return;
    }
    const workspaceLabel = currentWorkspaceId.trim() || "default";
    const timestamp = new Date().toISOString();
    const layoutJson = serializeLayoutPayload(layout, currentWorkspaceId);
    const xml = [
      '<?xml version="1.0" encoding="UTF-8"?>',
      "<FMWebIDELayoutExport>",
      `  <workspace>${escapeXmlText(workspaceLabel)}</workspace>`,
      `  <layoutId>${escapeXmlText(layout.id)}</layoutId>`,
      `  <layoutName>${escapeXmlText(layout.name || layout.id)}</layoutName>`,
      `  <exportedAt>${escapeXmlText(timestamp)}</exportedAt>`,
      `  <layoutJson>${wrapCData(layoutJson)}</layoutJson>`,
      "</FMWebIDELayoutExport>",
      ""
    ].join("\n");

    const blob = new Blob([xml], { type: "application/xml;charset=utf-8" });
    const downloadUrl = URL.createObjectURL(blob);
    const anchor = document.createElement("a");
    const baseName = toLayoutSlug(layout.name || layout.id);
    anchor.href = downloadUrl;
    anchor.download = `${baseName}-fmwebide.xml`;
    document.body.appendChild(anchor);
    anchor.click();
    anchor.remove();
    URL.revokeObjectURL(downloadUrl);
    setStatus(`Saved XML copy for layout ${layout.name || layout.id}`);
  }, [currentWorkspaceId, layout]);

  const createCustomMenu = useCallback(() => {
    const nextOrder = customMenusDraft.length + 1;
    const id = `menu-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 7)}`;
    const nextName = `Custom Menu ${nextOrder}`;
    const next: CustomMenuDefinition = {
      id,
      name: nextName,
      displayTitle: nextName,
      menuKey: "file",
      comment: "",
      creationOrder: nextOrder
    };
    setCustomMenusDraft((previous) => [...previous, next]);
    setCustomMenusSelectedId(id);
    setCustomMenuNameDraft(next.name);
    setCustomMenuDisplayTitleDraft(next.displayTitle ?? next.name);
    setCustomMenuKeyDraft(next.menuKey);
    setCustomMenuCommentDraft("");
  }, [customMenusDraft.length]);

  const duplicateCustomMenu = useCallback(() => {
    if (!selectedCustomMenuRow) {
      return;
    }
    const id = `menu-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 7)}`;
    const next: CustomMenuDefinition = {
      ...selectedCustomMenuRow,
      id,
      name: `${selectedCustomMenuRow.name} Copy`,
      displayTitle: selectedCustomMenuRow.displayTitle || selectedCustomMenuRow.name,
      locked: false,
      creationOrder: customMenusDraft.length + 1
    };
    setCustomMenusDraft((previous) => [...previous, next]);
    setCustomMenusSelectedId(id);
    setCustomMenuNameDraft(next.name);
    setCustomMenuDisplayTitleDraft(next.displayTitle ?? next.name);
    setCustomMenuKeyDraft(next.menuKey);
    setCustomMenuCommentDraft(next.comment ?? "");
  }, [customMenusDraft.length, selectedCustomMenuRow]);

  const deleteCustomMenu = useCallback(() => {
    if (!selectedCustomMenuRow || selectedCustomMenuRow.locked) {
      return;
    }
    const targetId = selectedCustomMenuRow.id;
    setCustomMenusDraft((previous) => previous.filter((entry) => entry.id !== targetId));
    setCustomMenuSetsDraft((previous) =>
      previous.map((entry) => ({
        ...entry,
        menuIds: entry.menuIds.filter((menuId) => menuId !== targetId)
      }))
    );
    setCustomMenusSelectedId("");
    setStatus(`Deleted custom menu ${selectedCustomMenuRow.name}`);
  }, [selectedCustomMenuRow]);

  const createCustomMenuSet = useCallback(() => {
    const nextOrder = customMenuSetsDraft.length + 1;
    const id = `menu-set-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 7)}`;
    const defaultMenuIds =
      customMenusDraft.length > 0 ? [customMenusDraft[0].id] : [];
    const next: CustomMenuSetDefinition = {
      id,
      name: `Custom Menu Set ${nextOrder}`,
      menuIds: defaultMenuIds,
      comment: "",
      creationOrder: nextOrder
    };
    setCustomMenuSetsDraft((previous) => [...previous, next]);
    setCustomMenuSetsSelectedId(id);
    setCustomMenuSetNameDraft(next.name);
    setCustomMenuSetCommentDraft("");
    setCustomMenuSetMenuIdsDraft(defaultMenuIds);
  }, [customMenuSetsDraft.length, customMenusDraft]);

  const duplicateCustomMenuSet = useCallback(() => {
    if (!selectedCustomMenuSetRow) {
      return;
    }
    const id = `menu-set-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 7)}`;
    const next: CustomMenuSetDefinition = {
      ...selectedCustomMenuSetRow,
      id,
      name: `${selectedCustomMenuSetRow.name} Copy`,
      locked: false,
      creationOrder: customMenuSetsDraft.length + 1
    };
    setCustomMenuSetsDraft((previous) => [...previous, next]);
    setCustomMenuSetsSelectedId(id);
    setCustomMenuSetNameDraft(next.name);
    setCustomMenuSetCommentDraft(next.comment ?? "");
    setCustomMenuSetMenuIdsDraft(next.menuIds);
  }, [customMenuSetsDraft.length, selectedCustomMenuSetRow]);

  const deleteCustomMenuSet = useCallback(() => {
    if (!selectedCustomMenuSetRow || selectedCustomMenuSetRow.locked) {
      return;
    }
    const targetId = selectedCustomMenuSetRow.id;
    const remaining = customMenuSetsDraft.filter((entry) => entry.id !== targetId);
    setCustomMenuSetsDraft(remaining);
    if (customMenuDefaultSetDraft === targetId) {
      setCustomMenuDefaultSetDraft(remaining[0]?.id ?? "");
    }
    setCustomMenuSetsSelectedId(remaining[0]?.id ?? "");
    setStatus(`Deleted custom menu set ${selectedCustomMenuSetRow.name}`);
  }, [customMenuDefaultSetDraft, customMenuSetsDraft, selectedCustomMenuSetRow]);

  const toggleCustomMenuSetMenuId = useCallback((menuId: string, checked: boolean) => {
    setCustomMenuSetMenuIdsDraft((previous) => {
      if (checked) {
        return [...new Set([...previous, menuId])];
      }
      return previous.filter((entry) => entry !== menuId);
    });
  }, []);

  const setCanvasBoolean = (
    key: "showGrid" | "snapToGrid" | "showRulers" | "showGuides" | "locked",
    value: boolean
  ) => {
    if (!layout) {
      return;
    }
    recordUndoSnapshot(layout);
    setLayout({
      ...layout,
      canvas: {
        ...layout.canvas,
        [key]: value
      }
    });
  };

  const setCanvasGridSize = (nextSize: number) => {
    if (!layout) {
      return;
    }
    const normalized = Math.max(1, Math.round(nextSize));
    if (normalized === layout.canvas.gridSize) {
      return;
    }
    recordUndoSnapshot(layout);
    setLayout({
      ...layout,
      canvas: {
        ...layout.canvas,
        gridSize: normalized
      }
    });
    setStatus(`Grid size set to ${normalized}px`);
  };

  const toggleCanvasDevicePreset = useCallback(
    (preset: DeviceCanvasPreset) => {
      if (!layout) {
        return;
      }
      const selectedPresetIds = normalizeCanvasDevicePresetIds(layout.canvas);
      const isSelected = selectedPresetIds.includes(preset.id);
      const nextPresetIds = isSelected
        ? selectedPresetIds.filter((presetId) => presetId !== preset.id)
        : [...selectedPresetIds, preset.id];
      const customFrame = normalizeCanvasCustomFrame(layout.canvas);
      const primaryPreset = layoutDevicePresets.find((entry) => entry.id === (nextPresetIds[0] ?? ""));
      recordUndoSnapshot(layout);
      setLayout({
        ...layout,
        canvas: {
          ...layout.canvas,
          deviceFramePresetIds: nextPresetIds,
          devicePresetId: primaryPreset
            ? primaryPreset.id
            : customFrame
              ? "custom"
              : "",
          deviceFrameWidth: primaryPreset
            ? primaryPreset.width
            : customFrame
              ? customFrame.width
              : undefined,
          deviceFrameHeight: primaryPreset
            ? primaryPreset.height
            : customFrame
              ? customFrame.height
              : undefined
        }
      });
      setStatus(
        isSelected
          ? `Device reference hidden: ${preset.label}`
          : `Device reference shown: ${preset.label}`
      );
    },
    [layout, recordUndoSnapshot]
  );

  const applyCustomDeviceFrame = useCallback(
    (width: number, height: number) => {
      if (!layout) {
        setCustomCanvasDialogOpen(false);
        return;
      }
      const normalizedWidth = Math.max(1, Math.round(width));
      const normalizedHeight = Math.max(1, Math.round(height));
      const selectedPresetIds = normalizeCanvasDevicePresetIds(layout.canvas);
      const primaryPreset = layoutDevicePresets.find((entry) => entry.id === (selectedPresetIds[0] ?? ""));
      const previousCustomFrame = normalizeCanvasCustomFrame(layout.canvas);
      if (
        previousCustomFrame &&
        previousCustomFrame.width === normalizedWidth &&
        previousCustomFrame.height === normalizedHeight
      ) {
        setCustomCanvasDialogOpen(false);
        return;
      }
      recordUndoSnapshot(layout);
      setLayout({
        ...layout,
        canvas: {
          ...layout.canvas,
          deviceFrameCustomWidth: normalizedWidth,
          deviceFrameCustomHeight: normalizedHeight,
          devicePresetId: primaryPreset ? primaryPreset.id : "custom",
          deviceFrameWidth: primaryPreset ? primaryPreset.width : normalizedWidth,
          deviceFrameHeight: primaryPreset ? primaryPreset.height : normalizedHeight
        }
      });
      setCustomCanvasDialogOpen(false);
      setStatus(`Custom device reference set to ${canvasDimensionLabel(normalizedWidth, normalizedHeight)}`);
    },
    [layout, recordUndoSnapshot]
  );

  const openCustomCanvasSizeDialog = useCallback(() => {
    if (!layout) {
      return;
    }
    setDevicePickerOpen(false);
    const customFrame = normalizeCanvasCustomFrame(layout.canvas);
    const firstFrame = resolveCanvasDeviceFrames(layout.canvas)[0] ?? null;
    setCustomCanvasWidth(String(customFrame?.width ?? firstFrame?.width ?? layout.canvas.width));
    setCustomCanvasHeight(String(customFrame?.height ?? firstFrame?.height ?? layout.canvas.height));
    setCustomCanvasDialogOpen(true);
    setStatus("Custom device reference size");
  }, [layout]);

  const applyCustomCanvasSize = useCallback(() => {
    if (!layout) {
      setCustomCanvasDialogOpen(false);
      return;
    }
    const customFrame = normalizeCanvasCustomFrame(layout.canvas);
    const fallbackFrame = resolveCanvasDeviceFrames(layout.canvas)[0] ?? null;
    const nextWidth = Math.max(
      1,
      Math.round(Number(customCanvasWidth) || customFrame?.width || fallbackFrame?.width || layout.canvas.width || 1024)
    );
    const nextHeight = Math.max(
      1,
      Math.round(Number(customCanvasHeight) || customFrame?.height || fallbackFrame?.height || layout.canvas.height || 720)
    );
    applyCustomDeviceFrame(nextWidth, nextHeight);
  }, [applyCustomDeviceFrame, customCanvasHeight, customCanvasWidth, layout]);

  const patchSelected = (updater: (component: LayoutComponent) => LayoutComponent) => {
    if (!layout || !selectedId) {
      return;
    }

    recordUndoSnapshot(layout);
    setLayout(updateComponent(layout, selectedId, updater));
  };

  const setSelectedPosition = (key: keyof LayoutComponent["position"], raw: string) => {
    const value = Number(raw);
    if (!Number.isFinite(value)) {
      return;
    }

    patchSelected((component) => ({
      ...component,
      position: {
        ...component.position,
        [key]: Math.round(value)
      }
    }));
  };

  const setSelectedProp = <K extends keyof LayoutComponent["props"]>(
    key: K,
    value: LayoutComponent["props"][K]
  ) => {
    patchSelected((component) => ({
      ...component,
      props: {
        ...component.props,
        [key]: value
      }
    }));
  };

  const applyThemeToFocusedLayout = useCallback(
    (rawThemeName: string) => {
      if (!layout) {
        return;
      }

      const nextThemeName = rawThemeName.trim();
      if (!nextThemeName) {
        return;
      }

      const nextThemeStyles = availableStylesByTheme[nextThemeName] ?? availableStyles;
      const fallbackStyleName = nextThemeStyles[0] ?? "Default";
      const nextThemeStyleSet = new Set(
        nextThemeStyles
          .map((styleName) => styleName.trim().toLowerCase())
          .filter((styleName) => styleName.length > 0)
      );

      recordUndoSnapshot(layout);
      setLayout({
        ...layout,
        components: layout.components.map((component) => {
          const currentStyleName = (component.props.styleName ?? "").trim();
          const keepCurrentStyle = currentStyleName
            ? nextThemeStyleSet.has(currentStyleName.toLowerCase())
            : false;
          return {
            ...component,
            props: {
              ...component.props,
              styleTheme: nextThemeName,
              styleName: keepCurrentStyle ? currentStyleName : fallbackStyleName
            }
          };
        })
      });
      setDefaultThemeName(nextThemeName);
      setStatus(`Applied theme "${nextThemeName}" to all objects on this layout`);
    },
    [availableStyles, availableStylesByTheme, layout, recordUndoSnapshot]
  );

  const changeThemeOptions = useMemo(() => {
    const names: string[] = [];
    const seen = new Set<string>();
    const appendTheme = (themeName: string) => {
      const trimmed = themeName.trim();
      if (!trimmed) {
        return;
      }
      const key = trimmed.toLowerCase();
      if (seen.has(key)) {
        return;
      }
      seen.add(key);
      names.push(trimmed);
    };
    (availableThemes.length > 0 ? availableThemes : [defaultThemeName]).forEach(appendTheme);
    appendTheme(defaultThemeName);
    appendTheme(changeThemeSelectedTheme);
    return names;
  }, [availableThemes, changeThemeSelectedTheme, defaultThemeName]);

  const closeChangeThemeDialog = useCallback(() => {
    setChangeThemeDialogOpen(false);
  }, []);

  const openChangeThemeDialog = useCallback(() => {
    const themeCounts = new Map<string, number>();
    if (layout) {
      for (const component of layout.components) {
        const themeName = (component.props.styleTheme ?? "").trim();
        if (!themeName) {
          continue;
        }
        themeCounts.set(themeName, (themeCounts.get(themeName) ?? 0) + 1);
      }
    }

    const mostUsedLayoutTheme = (() => {
      if (themeCounts.size === 0) {
        return defaultThemeName;
      }
      return [...themeCounts.entries()].sort((left, right) => {
        if (right[1] !== left[1]) {
          return right[1] - left[1];
        }
        return left[0].localeCompare(right[0]);
      })[0][0];
    })();

    setChangeThemeSelectedTheme(mostUsedLayoutTheme);
    closeLayoutMenu();
    setChangeThemeDialogOpen(true);
  }, [closeLayoutMenu, defaultThemeName, layout]);

  const applyChangeThemeDialog = useCallback(() => {
    const fallbackTheme = changeThemeOptions[0] ?? defaultThemeName;
    const nextThemeName = changeThemeSelectedTheme.trim() || fallbackTheme;
    if (!nextThemeName) {
      setStatus("No theme selected");
      return;
    }
    applyThemeToFocusedLayout(nextThemeName);
    setChangeThemeDialogOpen(false);
  }, [
    applyThemeToFocusedLayout,
    changeThemeOptions,
    changeThemeSelectedTheme,
    defaultThemeName
  ]);

  const setSelectedControlType = (controlType: LayoutComponent["props"]["controlType"]) => {
    patchSelected((component) => {
      const nextProps: LayoutComponent["props"] = {
        ...component.props,
        controlType
      };

      if (controlType === "popup") {
        if (nextProps.valueListIncludeArrow == null) {
          nextProps.valueListIncludeArrow = true;
        }
        if (nextProps.valueListAllowOtherValues == null) {
          nextProps.valueListAllowOtherValues = false;
        }
        if (nextProps.valueListAllowEditing == null) {
          nextProps.valueListAllowEditing = false;
        }
        if (nextProps.valueListOverrideFormatting == null) {
          nextProps.valueListOverrideFormatting = false;
        }
      } else if (controlType === "dropdown") {
        if (nextProps.valueListIncludeArrow == null) {
          nextProps.valueListIncludeArrow = true;
        }
        if (nextProps.valueListAllowEditing == null) {
          nextProps.valueListAllowEditing = false;
        }
      } else if (controlType === "checkbox") {
        if (nextProps.valueListAllowOtherValues == null) {
          nextProps.valueListAllowOtherValues = false;
        }
        if (nextProps.checkboxIcon == null) {
          nextProps.checkboxIcon = "x";
        }
      } else if (controlType === "radio") {
        if (nextProps.valueListAllowOtherValues == null) {
          nextProps.valueListAllowOtherValues = false;
        }
      } else if (controlType === "date") {
        if (nextProps.calendarIncludeIcon == null) {
          nextProps.calendarIncludeIcon = true;
        }
        if (nextProps.dateAutoCompleteExisting == null) {
          nextProps.dateAutoCompleteExisting = false;
        }
      } else if (controlType === "text") {
        if (nextProps.editShowVerticalScrollbar == null) {
          nextProps.editShowVerticalScrollbar = false;
        }
        if (nextProps.editVerticalScrollBehavior == null) {
          nextProps.editVerticalScrollBehavior = "always";
        }
        if (nextProps.editAutoCompleteExisting == null) {
          nextProps.editAutoCompleteExisting = false;
        }
      }

      return {
        ...component,
        props: nextProps
      };
    });
  };

  const setSelectedPropNumber = (key: keyof LayoutComponent["props"], raw: string) => {
    const value = Number(raw);
    if (!Number.isFinite(value)) {
      return;
    }
    setSelectedProp(key, Math.round(value));
  };

  const setSelectedLineSpacingHeight = (raw: string) => {
    const value = Number(raw);
    if (!Number.isFinite(value)) {
      return;
    }
    patchSelected((component) => ({
      ...component,
      props: {
        ...component.props,
        lineSpacing: value,
        lineSpacingHeight: value
      }
    }));
  };

  const addSelectedTabStop = () => {
    if (!selected) {
      return;
    }
    const tabStops = selected.props.tabStops ?? [];
    const lastValue = tabStops[tabStops.length - 1] ?? 0;
    setSelectedProp("tabStops", [...tabStops, lastValue + 36]);
  };

  const removeSelectedTabStop = () => {
    if (!selected) {
      return;
    }
    const tabStops = selected.props.tabStops ?? [];
    if (tabStops.length === 0) {
      return;
    }
    setSelectedProp("tabStops", tabStops.slice(0, -1));
  };

  const setSelectedTabStopAt = (index: number, raw: string) => {
    if (!selected) {
      return;
    }
    const value = Number(raw);
    if (!Number.isFinite(value)) {
      return;
    }
    const tabStops = [...(selected.props.tabStops ?? [])];
    tabStops[index] = Math.max(0, Math.round(value));
    setSelectedProp("tabStops", tabStops);
  };

  const resolveSelectionIds = useCallback(
    (options?: { includeGrouped?: boolean; unlockedOnly?: boolean; explicitOnly?: boolean }) => {
      if (!layout) {
        return [] as string[];
      }

      const includeGrouped = options?.includeGrouped !== false;
      const unlockedOnly = options?.unlockedOnly === true;
      const explicitOnly = options?.explicitOnly === true;
      const validIdSet = new Set(layout.components.map((component) => component.id));
      const seedIds = (explicitOnly ? selectedComponentIds : activeSelectionIds).filter((id) =>
        validIdSet.has(id)
      );
      const ids = new Set(seedIds);

      if (!explicitOnly && ids.size === 0 && selectedId && validIdSet.has(selectedId)) {
        ids.add(selectedId);
      }

      if (includeGrouped) {
        const selectedGroupIds = new Set<string>();
        for (const id of ids) {
          const component = layout.components.find((entry) => entry.id === id);
          const groupId = component?.props.groupId?.trim();
          if (groupId) {
            selectedGroupIds.add(groupId);
          }
        }
        if (selectedGroupIds.size > 0) {
          for (const component of layout.components) {
            const groupId = component.props.groupId?.trim();
            if (groupId && selectedGroupIds.has(groupId)) {
              ids.add(component.id);
            }
          }
        }
      }

      const ordered = layout.components
        .filter((component) => ids.has(component.id))
        .map((component) => component.id);

      if (!unlockedOnly) {
        return ordered;
      }

      return ordered.filter((id) => {
        const component = layout.components.find((entry) => entry.id === id);
        return component?.props.locked !== true;
      });
    },
    [activeSelectionIds, layout, selectedComponentIds, selectedId]
  );

  const resolveArrangeActionState = useCallback(
    (selectionSeedIds?: string[]): ArrangeActionState => {
      const disabledState: ArrangeActionState = {
        group: false,
        ungroup: false,
        addToGroup: false,
        removeFromGroup: false,
        lock: false,
        unlock: false,
        bringFront: false,
        bringForward: false,
        sendBack: false,
        sendBackward: false,
        rotate: false,
        align: false,
        distribute: false,
        resize: false
      };
      if (!layout) {
        return disabledState;
      }

      const validIds = new Set(layout.components.map((component) => component.id));
      const explicitIds = (() => {
        if (selectionSeedIds && selectionSeedIds.length > 0) {
          return [...new Set(selectionSeedIds.filter((id) => validIds.has(id)))];
        }
        const seeded = activeSelectionIds.filter((id) => validIds.has(id));
        if (seeded.length > 0) {
          return [...new Set(seeded)];
        }
        if (selectedId && validIds.has(selectedId)) {
          return [selectedId];
        }
        return [] as string[];
      })();
      if (explicitIds.length === 0) {
        return disabledState;
      }

      const componentsById = new Map(layout.components.map((component) => [component.id, component]));
      const explicitComponents = explicitIds
        .map((id) => componentsById.get(id))
        .filter((component): component is LayoutComponent => Boolean(component));
      const explicitUnlocked = explicitComponents.filter((component) => component.props.locked !== true);
      const explicitLocked = explicitComponents.filter((component) => component.props.locked === true);
      const selectedGroupIds = new Set(
        explicitComponents
          .map((component) => component.props.groupId?.trim() ?? "")
          .filter((groupId) => groupId.length > 0)
      );
      const explicitUngroupedUnlocked = explicitUnlocked.filter(
        (component) => !(component.props.groupId?.trim() ?? "")
      );
      const explicitGroupedUnlocked = explicitUnlocked.filter((component) =>
        Boolean(component.props.groupId?.trim() ?? "")
      );

      const expandedIds = new Set(explicitIds);
      if (selectedGroupIds.size > 0) {
        for (const component of layout.components) {
          const groupId = component.props.groupId?.trim();
          if (groupId && selectedGroupIds.has(groupId)) {
            expandedIds.add(component.id);
          }
        }
      }
      const expandedComponents = layout.components.filter((component) => expandedIds.has(component.id));
      const expandedUnlocked = expandedComponents.filter((component) => component.props.locked !== true);
      const expandedLocked = expandedComponents.filter((component) => component.props.locked === true);
      const expandedUnlockedSet = new Set(expandedUnlocked.map((component) => component.id));

      const ordered = sortComponentsByArrangeOrder(layout.components);
      const selectedCount = expandedUnlockedSet.size;
      const canBringForward =
        selectedCount > 0 &&
        ordered.some((component, index) =>
          expandedUnlockedSet.has(component.id) &&
          index < ordered.length - 1 &&
          !expandedUnlockedSet.has(ordered[index + 1]?.id ?? "")
        );
      const canSendBackward =
        selectedCount > 0 &&
        ordered.some((component, index) =>
          expandedUnlockedSet.has(component.id) &&
          index > 0 &&
          !expandedUnlockedSet.has(ordered[index - 1]?.id ?? "")
        );
      const trailingSelectedCount = (() => {
        let count = 0;
        for (let index = ordered.length - 1; index >= 0; index -= 1) {
          if (!expandedUnlockedSet.has(ordered[index].id)) {
            break;
          }
          count += 1;
        }
        return count;
      })();
      const leadingSelectedCount = (() => {
        let count = 0;
        for (let index = 0; index < ordered.length; index += 1) {
          if (!expandedUnlockedSet.has(ordered[index].id)) {
            break;
          }
          count += 1;
        }
        return count;
      })();
      const canBringFront = selectedCount > 0 && trailingSelectedCount < selectedCount;
      const canSendBack = selectedCount > 0 && leadingSelectedCount < selectedCount;

      return {
        group: explicitUnlocked.length >= 2,
        ungroup: selectedGroupIds.size > 0,
        addToGroup:
          selectedGroupIds.size > 0 &&
          explicitUngroupedUnlocked.length > 0 &&
          explicitComponents.length >= 2,
        removeFromGroup: explicitGroupedUnlocked.length > 0,
        lock: expandedUnlocked.length > 0,
        unlock: expandedLocked.length > 0 || explicitLocked.length > 0,
        bringFront: canBringFront,
        bringForward: canBringForward,
        sendBack: canSendBack,
        sendBackward: canSendBackward,
        rotate: expandedUnlocked.length > 0,
        align: expandedUnlocked.length > 0,
        distribute: expandedUnlocked.length >= 3,
        resize: expandedUnlocked.length >= 2
      };
    },
    [activeSelectionIds, layout, selectedId]
  );

  const arrangeActionState = useMemo(
    () => resolveArrangeActionState(),
    [resolveArrangeActionState]
  );
  const contextArrangeActionState = useMemo(() => {
    const contextComponentId = contextMenu?.componentId ?? "";
    if (!contextComponentId) {
      return arrangeActionState;
    }
    const seedIds = activeSelectionIds.includes(contextComponentId)
      ? activeSelectionIds
      : [contextComponentId];
    return resolveArrangeActionState(seedIds);
  }, [activeSelectionIds, arrangeActionState, contextMenu?.componentId, resolveArrangeActionState]);

  const contextSubmenuItems = useMemo(() => {
    if (!contextSubmenu) {
      return [] as ContextSubmenuItem[];
    }

    if (contextSubmenu.entryId === "object-style") {
      return [
        { id: "default", label: "Default" },
        { id: "border-secondary", label: "Border | Secondary" },
        { id: "fill-secondary", label: "Fill | Secondary" },
        { id: "fill-inverted", label: "Fill | Inverted" }
      ];
    }

    if (contextSubmenu.entryId === "fill-color") {
      return [
        { id: "none", label: "None" },
        { id: "#ffffff", label: "White", swatch: "#ffffff" },
        { id: "#f8fafc", label: "Gray 50", swatch: "#f8fafc" },
        { id: "#e2e8f0", label: "Gray 200", swatch: "#e2e8f0" },
        { id: "#dbeafe", label: "Blue 100", swatch: "#dbeafe" },
        { id: "#dcfce7", label: "Green 100", swatch: "#dcfce7" },
        { id: "#fee2e2", label: "Red 100", swatch: "#fee2e2" }
      ];
    }

    if (contextSubmenu.entryId === "pen-color") {
      return [
        { id: "#111827", label: "Black", swatch: "#111827" },
        { id: "#334155", label: "Slate", swatch: "#334155" },
        { id: "#64748b", label: "Gray", swatch: "#64748b" },
        { id: "#1d4ed8", label: "Blue", swatch: "#1d4ed8" },
        { id: "#16a34a", label: "Green", swatch: "#16a34a" },
        { id: "#dc2626", label: "Red", swatch: "#dc2626" }
      ];
    }

    if (contextSubmenu.entryId === "pen-width") {
      return [
        { id: "0", label: "0 px (None)" },
        { id: "1", label: "1 px" },
        { id: "2", label: "2 px" },
        { id: "3", label: "3 px" },
        { id: "4", label: "4 px" }
      ];
    }

    if (contextSubmenu.entryId === "arrange") {
      return [
        { id: "arrange-group", label: "Group", disabled: !contextArrangeActionState.group },
        { id: "arrange-ungroup", label: "Ungroup", disabled: !contextArrangeActionState.ungroup },
        { id: "arrange-add-to-group", label: "Add to Group", disabled: !contextArrangeActionState.addToGroup },
        {
          id: "arrange-remove-from-group",
          label: "Remove from Group",
          disabled: !contextArrangeActionState.removeFromGroup
        },
        { id: "arrange-lock", label: "Lock", dividerBefore: true, disabled: !contextArrangeActionState.lock },
        { id: "arrange-unlock", label: "Unlock", disabled: !contextArrangeActionState.unlock },
        {
          id: "arrange-bring-front",
          label: "Bring to Front",
          dividerBefore: true,
          disabled: !contextArrangeActionState.bringFront
        },
        {
          id: "arrange-bring-forward",
          label: "Bring Forward",
          disabled: !contextArrangeActionState.bringForward
        },
        {
          id: "arrange-send-back",
          label: "Send to Back",
          disabled: !contextArrangeActionState.sendBack
        },
        {
          id: "arrange-send-backward",
          label: "Send Backward",
          disabled: !contextArrangeActionState.sendBackward
        },
        {
          id: "arrange-rotate-90",
          label: "Rotate 90°",
          dividerBefore: true,
          disabled: !contextArrangeActionState.rotate
        },
        {
          id: "arrange-align-left",
          label: "Align Left",
          dividerBefore: true,
          disabled: !contextArrangeActionState.align
        },
        { id: "arrange-align-center-h", label: "Center H", disabled: !contextArrangeActionState.align },
        { id: "arrange-align-right", label: "Align Right", disabled: !contextArrangeActionState.align },
        { id: "arrange-align-top", label: "Align Top", disabled: !contextArrangeActionState.align },
        { id: "arrange-align-center-v", label: "Center V", disabled: !contextArrangeActionState.align },
        { id: "arrange-align-bottom", label: "Align Bottom", disabled: !contextArrangeActionState.align },
        {
          id: "arrange-distribute-horizontal",
          label: "Distribute Horizontally",
          dividerBefore: true,
          disabled: !contextArrangeActionState.distribute
        },
        {
          id: "arrange-distribute-vertical",
          label: "Distribute Vertically",
          disabled: !contextArrangeActionState.distribute
        },
        {
          id: "arrange-resize-widest",
          label: "Resize Widest",
          dividerBefore: true,
          disabled: !contextArrangeActionState.resize
        },
        { id: "arrange-resize-narrowest", label: "Resize Narrowest", disabled: !contextArrangeActionState.resize },
        { id: "arrange-resize-tallest", label: "Resize Tallest", disabled: !contextArrangeActionState.resize },
        { id: "arrange-resize-shortest", label: "Resize Shortest", disabled: !contextArrangeActionState.resize }
      ];
    }

    return [] as ContextSubmenuItem[];
  }, [contextArrangeActionState, contextSubmenu]);

  const applySelectionComponentPatch = useCallback(
    (
      selectionIds: string[],
      updater: (component: LayoutComponent) => LayoutComponent,
      statusText?: string
    ) => {
      if (!layout || selectionIds.length === 0) {
        return false;
      }
      const selectedSet = new Set(selectionIds);
      const nextComponents = layout.components.map((component) =>
        selectedSet.has(component.id) ? updater(component) : component
      );
      recordUndoSnapshot(layout);
      setLayout({
        ...layout,
        components: nextComponents
      });
      if (statusText) {
        setStatus(statusText);
      }
      return true;
    },
    [layout, recordUndoSnapshot]
  );

  const alignSelectedToCanvas = (
    axis: "left" | "centerX" | "right" | "top" | "centerY" | "bottom"
  ) => {
    if (!layout || !selected || selected.props.locked === true) {
      return;
    }

    const canvasWidth = layout.canvas.width;
    const canvasHeight = layout.canvas.height;
    patchSelected((component) => {
      const next = { ...component.position };
      if (axis === "left") {
        next.x = 0;
      } else if (axis === "centerX") {
        next.x = Math.max(0, Math.round((canvasWidth - next.width) / 2));
      } else if (axis === "right") {
        next.x = Math.max(0, canvasWidth - next.width);
      } else if (axis === "top") {
        next.y = 0;
      } else if (axis === "centerY") {
        next.y = Math.max(0, Math.round((canvasHeight - next.height) / 2));
      } else if (axis === "bottom") {
        next.y = Math.max(0, canvasHeight - next.height);
      }
      return {
        ...component,
        position: next
      };
    });
  };

  const alignSelectedObjects = useCallback(
    (axis: "left" | "centerX" | "right" | "top" | "centerY" | "bottom") => {
      if (!layout) {
        return;
      }
      const selectionIds = resolveSelectionIds({ includeGrouped: true, unlockedOnly: true });
      if (selectionIds.length === 0) {
        setStatus("No unlocked object selected");
        return;
      }
      if (selectionIds.length === 1) {
        alignSelectedToCanvas(axis);
        return;
      }

      const selectedComponents = layout.components.filter((component) => selectionIds.includes(component.id));
      if (selectedComponents.length < 2) {
        return;
      }
      const left = Math.min(...selectedComponents.map((component) => component.position.x));
      const right = Math.max(...selectedComponents.map((component) => component.position.x + component.position.width));
      const top = Math.min(...selectedComponents.map((component) => component.position.y));
      const bottom = Math.max(...selectedComponents.map((component) => component.position.y + component.position.height));
      const centerX = (left + right) / 2;
      const centerY = (top + bottom) / 2;
      applySelectionComponentPatch(
        selectionIds,
        (component) => {
          const next = { ...component.position };
          if (axis === "left") {
            next.x = left;
          } else if (axis === "centerX") {
            next.x = Math.round(centerX - component.position.width / 2);
          } else if (axis === "right") {
            next.x = Math.round(right - component.position.width);
          } else if (axis === "top") {
            next.y = top;
          } else if (axis === "centerY") {
            next.y = Math.round(centerY - component.position.height / 2);
          } else if (axis === "bottom") {
            next.y = Math.round(bottom - component.position.height);
          }
          return {
            ...component,
            position: next
          };
        },
        "Aligned selected objects"
      );
    },
    [alignSelectedToCanvas, applySelectionComponentPatch, layout, resolveSelectionIds]
  );

  const distributeSelectedObjects = useCallback(
    (axis: "horizontal" | "vertical") => {
      if (!layout) {
        return;
      }
      const selectionIds = resolveSelectionIds({ includeGrouped: true, unlockedOnly: true });
      if (selectionIds.length < 3) {
        setStatus("Select at least 3 unlocked objects to distribute");
        return;
      }
      const selectedComponents = layout.components
        .filter((component) => selectionIds.includes(component.id))
        .sort((left, right) =>
          axis === "horizontal"
            ? left.position.x - right.position.x || left.position.z - right.position.z
            : left.position.y - right.position.y || left.position.z - right.position.z
        );
      const first = selectedComponents[0];
      const last = selectedComponents[selectedComponents.length - 1];
      if (!first || !last) {
        return;
      }

      const interior = selectedComponents.slice(1, -1);
      const targetById = new Map<string, number>();
      if (interior.length > 0) {
        if (axis === "horizontal") {
          const firstRight = first.position.x + first.position.width;
          const lastLeft = last.position.x;
          const interiorWidth = interior.reduce((sum, component) => sum + component.position.width, 0);
          const gap = (lastLeft - firstRight - interiorWidth) / Math.max(1, selectedComponents.length - 1);
          let cursor = firstRight + gap;
          for (const component of interior) {
            targetById.set(component.id, Math.round(cursor));
            cursor += component.position.width + gap;
          }
        } else {
          const firstBottom = first.position.y + first.position.height;
          const lastTop = last.position.y;
          const interiorHeight = interior.reduce((sum, component) => sum + component.position.height, 0);
          const gap = (lastTop - firstBottom - interiorHeight) / Math.max(1, selectedComponents.length - 1);
          let cursor = firstBottom + gap;
          for (const component of interior) {
            targetById.set(component.id, Math.round(cursor));
            cursor += component.position.height + gap;
          }
        }
      }

      applySelectionComponentPatch(
        selectionIds,
        (component) => {
          const next = { ...component.position };
          const target = targetById.get(component.id);
          if (target == null) {
            return component;
          }
          if (axis === "horizontal") {
            next.x = target;
          } else {
            next.y = target;
          }
          return {
            ...component,
            position: next
          };
        },
        axis === "horizontal"
          ? "Distributed objects horizontally"
          : "Distributed objects vertically"
      );
    },
    [applySelectionComponentPatch, layout, resolveSelectionIds]
  );

  const resizeSelectedObjects = useCallback(
    (mode: "widest" | "narrowest" | "tallest" | "shortest") => {
      if (!layout) {
        return;
      }
      const selectionIds = resolveSelectionIds({ includeGrouped: true, unlockedOnly: true });
      if (selectionIds.length < 2) {
        setStatus("Select at least 2 unlocked objects to resize");
        return;
      }
      const selectedComponents = layout.components.filter((component) =>
        selectionIds.includes(component.id)
      );
      const widths = selectedComponents.map((component) => component.position.width);
      const heights = selectedComponents.map((component) => component.position.height);
      const targetWidth =
        mode === "widest"
          ? Math.max(...widths)
          : mode === "narrowest"
            ? Math.min(...widths)
            : null;
      const targetHeight =
        mode === "tallest"
          ? Math.max(...heights)
          : mode === "shortest"
            ? Math.min(...heights)
            : null;

      applySelectionComponentPatch(
        selectionIds,
        (component) => {
          const next = { ...component.position };
          if (targetWidth != null) {
            next.width = Math.max(12, targetWidth);
          }
          if (targetHeight != null) {
            next.height = Math.max(8, targetHeight);
          }
          return {
            ...component,
            position: next
          };
        },
        mode === "widest"
          ? "Resized objects to widest"
          : mode === "narrowest"
            ? "Resized objects to narrowest"
            : mode === "tallest"
              ? "Resized objects to tallest"
              : "Resized objects to shortest"
      );
    },
    [applySelectionComponentPatch, layout, resolveSelectionIds]
  );

  const setSelectedObjectsLocked = useCallback(
    (locked: boolean) => {
      const selectionIds = resolveSelectionIds({ includeGrouped: true, unlockedOnly: false }).filter((id) => {
        const component = layout?.components.find((entry) => entry.id === id);
        if (!component) {
          return false;
        }
        return locked ? component.props.locked !== true : component.props.locked === true;
      });
      if (selectionIds.length === 0) {
        setStatus(locked ? "No unlocked object selected" : "No locked object selected");
        return;
      }
      applySelectionComponentPatch(
        selectionIds,
        (component) => ({
          ...component,
          props: {
            ...component.props,
            locked
          }
        }),
        locked ? "Locked selected objects" : "Unlocked selected objects"
      );
    },
    [applySelectionComponentPatch, layout, resolveSelectionIds]
  );

  const rotateSelectedObjects = useCallback(
    (degrees: number) => {
      const selectionIds = resolveSelectionIds({ includeGrouped: true, unlockedOnly: true });
      if (selectionIds.length === 0) {
        setStatus("No unlocked object selected");
        return;
      }
      applySelectionComponentPatch(
        selectionIds,
        (component) => ({
          ...component,
          props: {
            ...component.props,
            rotation: ((Number(component.props.rotation ?? 0) + degrees) % 360 + 360) % 360
          }
        }),
        `Rotated selected objects ${degrees >= 0 ? "+" : ""}${degrees}°`
      );
    },
    [applySelectionComponentPatch, resolveSelectionIds]
  );

  const setGroupForSelectedObjects = useCallback(
    (mode: "group" | "ungroup" | "add" | "remove") => {
      if (!layout) {
        return;
      }
      const explicitSelectionIds = resolveSelectionIds({
        includeGrouped: false,
        explicitOnly: true,
        unlockedOnly: mode !== "ungroup"
      });
      if (explicitSelectionIds.length === 0) {
        setStatus("No eligible object selected");
        return;
      }

      if (mode === "group") {
        if (explicitSelectionIds.length < 2) {
          setStatus("Select at least 2 unlocked objects to group");
          return;
        }
        const groupId = crypto.randomUUID();
        applySelectionComponentPatch(
          explicitSelectionIds,
          (component) => ({
            ...component,
            props: {
              ...component.props,
              groupId
            }
          }),
          "Grouped selected objects"
        );
        return;
      }

      if (mode === "ungroup") {
        const selectedGroupIds = new Set<string>();
        for (const id of resolveSelectionIds({ includeGrouped: true, explicitOnly: false })) {
          const component = layout.components.find((entry) => entry.id === id);
          const groupId = component?.props.groupId?.trim();
          if (groupId) {
            selectedGroupIds.add(groupId);
          }
        }
        if (selectedGroupIds.size === 0) {
          setStatus("Selection is not grouped");
          return;
        }
        const targetIds = layout.components
          .filter((component) => {
            const groupId = component.props.groupId?.trim();
            return Boolean(groupId && selectedGroupIds.has(groupId));
          })
          .map((component) => component.id);
        applySelectionComponentPatch(
          targetIds,
          (component) => ({
            ...component,
            props: {
              ...component.props,
              groupId: undefined
            }
          }),
          "Ungrouped selected objects"
        );
        return;
      }

      if (mode === "remove") {
        const groupedIds = explicitSelectionIds.filter((id) => {
          const component = layout.components.find((entry) => entry.id === id);
          return Boolean(component?.props.groupId?.trim());
        });
        if (groupedIds.length === 0) {
          setStatus("Selection is not grouped");
          return;
        }
        applySelectionComponentPatch(
          groupedIds,
          (component) => ({
            ...component,
            props: {
              ...component.props,
              groupId: undefined
            }
          }),
          "Removed objects from group"
        );
        return;
      }

      const targetGroupId = (() => {
        const groupedSelection = resolveSelectionIds({ includeGrouped: false, explicitOnly: true });
        for (const id of groupedSelection) {
          const component = layout.components.find((entry) => entry.id === id);
          const groupId = component?.props.groupId?.trim();
          if (groupId) {
            return groupId;
          }
        }
        return "";
      })();
      if (!targetGroupId) {
        setStatus("Select at least one grouped object and one ungrouped object");
        return;
      }
      applySelectionComponentPatch(
        explicitSelectionIds,
        (component) => ({
          ...component,
          props: {
            ...component.props,
            groupId: targetGroupId
          }
        }),
        "Added objects to group"
      );
    },
    [applySelectionComponentPatch, layout, resolveSelectionIds]
  );

  const moveSelectedLayer = useCallback(
    (direction: "front" | "back" | "forward" | "backward", selectionOverrideIds?: string[]) => {
      if (!layout) {
        return;
      }
      const selectionIds = (() => {
        if (!selectionOverrideIds || selectionOverrideIds.length === 0) {
          return resolveSelectionIds({ includeGrouped: true, unlockedOnly: true });
        }

        const validIds = new Set(layout.components.map((component) => component.id));
        const selectedSet = new Set(selectionOverrideIds.filter((id) => validIds.has(id)));
        if (selectedSet.size === 0) {
          return [] as string[];
        }

        const selectedGroupIds = new Set<string>();
        for (const id of selectedSet) {
          const component = layout.components.find((entry) => entry.id === id);
          const groupId = component?.props.groupId?.trim();
          if (groupId) {
            selectedGroupIds.add(groupId);
          }
        }
        if (selectedGroupIds.size > 0) {
          for (const component of layout.components) {
            const groupId = component.props.groupId?.trim();
            if (groupId && selectedGroupIds.has(groupId)) {
              selectedSet.add(component.id);
            }
          }
        }

        return layout.components
          .filter((component) => selectedSet.has(component.id) && component.props.locked !== true)
          .map((component) => component.id);
      })();
      if (selectionIds.length === 0) {
        setStatus("No unlocked object selected");
        return;
      }

      const selectedSet = new Set(selectionIds);
      const ordered = sortComponentsByArrangeOrder(layout.components);
      let nextOrder = [...ordered];

      if (direction === "front") {
        nextOrder = [...ordered.filter((component) => !selectedSet.has(component.id)), ...ordered.filter((component) => selectedSet.has(component.id))];
      } else if (direction === "back") {
        nextOrder = [...ordered.filter((component) => selectedSet.has(component.id)), ...ordered.filter((component) => !selectedSet.has(component.id))];
      } else if (direction === "forward") {
        for (let index = nextOrder.length - 2; index >= 0; index -= 1) {
          if (selectedSet.has(nextOrder[index].id) && !selectedSet.has(nextOrder[index + 1].id)) {
            const temp = nextOrder[index];
            nextOrder[index] = nextOrder[index + 1];
            nextOrder[index + 1] = temp;
          }
        }
      } else {
        for (let index = 1; index < nextOrder.length; index += 1) {
          if (selectedSet.has(nextOrder[index].id) && !selectedSet.has(nextOrder[index - 1].id)) {
            const temp = nextOrder[index];
            nextOrder[index] = nextOrder[index - 1];
            nextOrder[index - 1] = temp;
          }
        }
      }

      const zById = new Map<string, number>();
      nextOrder.forEach((component, index) => {
        zById.set(component.id, index + 1);
      });
      recordUndoSnapshot(layout);
      setLayout({
        ...layout,
        components: layout.components.map((component) => ({
          ...component,
          position: {
            ...component.position,
            z: zById.get(component.id) ?? component.position.z
          }
        }))
      });
      setStatus(
        direction === "front"
          ? "Brought selected objects to front"
          : direction === "back"
            ? "Sent selected objects to back"
            : direction === "forward"
              ? "Brought selected objects forward"
              : "Sent selected objects backward"
      );
    },
    [layout, recordUndoSnapshot, resolveSelectionIds]
  );

  const selectedTooltip = selected?.props.tooltip ?? "";
  const selectedPlaceholder = selected?.props.placeholder ?? "";
  const selectedField = selected?.binding?.field ?? "";
  const selectedFieldTableOccurrence =
    selected?.binding?.tableOccurrence ?? layout?.defaultTableOccurrence ?? "";
  const selectedFieldType = (() => {
    if (!selectedField.trim()) {
      return "";
    }
    const entries = fieldsByTableOccurrence[selectedFieldTableOccurrence] ?? [];
    const normalizedSelectedField = unqualifiedFieldName(selectedField).toLowerCase();
    const directMatch = entries.find((entry) => entry.name.trim().toLowerCase() === normalizedSelectedField);
    if (directMatch) {
      return directMatch.type;
    }
    const relatedMatch = availableFields.find(
      (entry) => unqualifiedFieldName(entry.name).toLowerCase() === normalizedSelectedField
    );
    return relatedMatch?.type ?? "";
  })();
  const selectedIsContainerField =
    selected?.type === "field" &&
    (selectedFieldType.toLowerCase().includes("container") ||
      isLikelyContainerFieldName(selectedField) ||
      typeof selected?.props.containerFormat === "string" ||
      typeof selected?.props.containerOptimizeFor === "string");
  const selectedControlType = selected?.props.controlType ?? "text";
  const selectedControlUsesValueList =
    selectedControlType === "dropdown" ||
    selectedControlType === "popup" ||
    selectedControlType === "radio" ||
    selectedControlType === "checkbox";
  const selectedValueListName = selected?.props.valueList ?? "";
  const selectedValueListValues = selectedValueListName
    ? availableValueLists.find((entry) => entry.name === selectedValueListName)?.values ?? []
    : [];
  const selectedValueListIncludeArrow = selected?.props.valueListIncludeArrow !== false;
  const selectedValueListAllowOtherValues = Boolean(selected?.props.valueListAllowOtherValues);
  const selectedValueListAllowEditing = Boolean(selected?.props.valueListAllowEditing);
  const selectedValueListOverrideFormatting = Boolean(selected?.props.valueListOverrideFormatting);
  const selectedCheckboxIcon = selected?.props.checkboxIcon ?? "x";
  const selectedEditShowVerticalScrollbar = Boolean(selected?.props.editShowVerticalScrollbar);
  const selectedEditVerticalScrollBehavior = selected?.props.editVerticalScrollBehavior ?? "always";
  const selectedEditAutoCompleteExisting = Boolean(selected?.props.editAutoCompleteExisting);
  const selectedCalendarIncludeIcon = selected?.props.calendarIncludeIcon !== false;
  const selectedDateAutoCompleteExisting = Boolean(selected?.props.dateAutoCompleteExisting);
  const selectedScript = selected?.events?.onClick?.script ?? "";
  const selectedParameter = selected?.events?.onClick?.parameter ?? "";
  const buttonSetupIsPopover = buttonSetupMode === "popover";
  const selectedUrlTemplate = selected?.props.webViewerUrlTemplate ?? "";
  const selectedTheme = selected?.props.styleTheme ?? defaultThemeName;
  const selectedStyleName = selected?.props.styleName ?? "Default";
  const stylesForSelectedTheme = availableStylesByTheme[selectedTheme] ?? availableStyles;
  const selectableStyleNames = (() => {
    const baseline = stylesForSelectedTheme.length ? [...stylesForSelectedTheme] : ["Default"];
    if (!baseline.includes(selectedStyleName)) {
      baseline.push(selectedStyleName);
    }
    return baseline;
  })();
  const styleTargetsForSelectedThemeByLowerName = useMemo(() => {
    const byStyleName = availableStyleTargetsByTheme[selectedTheme] ?? {};
    const normalized: Record<string, string[]> = {};
    for (const [styleName, targets] of Object.entries(byStyleName)) {
      const cleanedName = styleName.trim().toLowerCase();
      if (!cleanedName) {
        continue;
      }
      normalized[cleanedName] = normalizeStyleTargetLabels(targets);
    }
    return normalized;
  }, [availableStyleTargetsByTheme, selectedTheme]);
  const groupedStyleNames = useMemo(
    () => buildThemeStyleGroups(selectableStyleNames, styleTargetsForSelectedThemeByLowerName),
    [selectableStyleNames, styleTargetsForSelectedThemeByLowerName]
  );
  const visibleStyleNames = showAllStyles
    ? selectableStyleNames
    : selectableStyleNames.filter(
        (styleName, index) => index < 8 || styleName === "Default" || styleName === selectedStyleName
      );
  const selectedLeft = selected?.position.x ?? 0;
  const selectedTop = selected?.position.y ?? 0;
  const selectedRight = layout && selected ? layout.canvas.width - (selected.position.x + selected.position.width) : 0;
  const selectedBottom = layout && selected ? layout.canvas.height - (selected.position.y + selected.position.height) : 0;
  const selectedObjectName = selected?.props.label || selected?.binding?.field || "";
  const selectedObjectTypeLabel = selected
    ? selected.type === "field"
      ? "Field"
      : selected.type === "button"
        ? selected.props.buttonMode === "bar"
          ? "Button Bar"
          : selected.props.buttonMode === "popover"
            ? "Popover Button"
            : "Button"
        : selected.type === "portal"
          ? "Portal"
          : selected.type === "panel"
            ? (selected.props.panelType ?? "tab") === "slide"
              ? "Slide Control"
              : "Tab Control"
            : selected.type === "shape"
              ? "Graphic"
              : selected.type === "webViewer"
                ? "Web Viewer"
                : selected.type === "chart"
                  ? "Chart"
                  : selected.type === "label"
                    ? "Text"
                    : "Object"
    : "";
  const selectedObjectBindingLabel = selected?.binding?.field?.trim() ?? "";
  const selectedObjectContextLabel = selected?.binding?.tableOccurrence?.trim() ?? layout?.defaultTableOccurrence ?? "";
  const selectedObjectDisplayName =
    selectedObjectName.trim() || selectedObjectBindingLabel || (selected ? selected.id.slice(0, 8) : "");
  const selectedFillType = selected?.props.fillType ?? "solid";
  const selectedFillColor = selected?.props.fillColor ?? "#ffffff";
  const selectedFillGradientStart = selected?.props.fillGradientStartColor ?? selectedFillColor;
  const selectedFillGradientEnd = selected?.props.fillGradientEndColor ?? "#e2e8f0";
  const selectedFillGradientAngle = selected?.props.fillGradientAngle ?? 180;
  const selectedFillImageUrl = selected?.props.fillImageUrl ?? "";
  const selectedLineColor = selected?.props.lineColor ?? "#cbd5e1";
  const selectedTextColor = selected?.props.textColor ?? "#0f172a";
  const selectedLineStyle = selected?.props.lineStyle ?? "solid";
  const selectedLineWidth = selected?.props.lineWidth ?? 1;
  const selectedCornerRadius = selected?.props.cornerRadius ?? 0;
  const selectedFontFamily = selected?.props.fontFamily ?? "Arial";
  const selectedFontSize = selected?.props.fontSize ?? 14;
  const selectedFontWeight = selected?.props.fontWeight ?? "regular";
  const selectedTextUnderline = Boolean(selected?.props.textUnderline);
  const selectedFontBoldActive = selectedFontWeight === "bold" || selectedFontWeight === "boldItalic";
  const selectedFontItalicActive = selectedFontWeight === "italic" || selectedFontWeight === "boldItalic";
  const selectedTextAlign = selected?.props.textAlign ?? "left";
  const selectedCanFormatText = Boolean(selected) && selected?.type !== "shape";
  const isLayoutInsertToolActive =
    activeTool === "portal" ||
    Boolean(
      activeTextTool ||
      activeShapeTool ||
      activeFieldTool ||
      activeButtonTool ||
      activePanelTool ||
      activeWebViewerTool ||
      activeChartTool
    );
  const selectedFontSizeOption = String(Math.max(1, Math.round(Number(selectedFontSize) || 14)));
  const selectedFontFamilyOption = selectedFontFamily.trim() || "Arial";
  const hasSelectedFontSizePreset = formattingBarFontSizes.some((size) => String(size) === selectedFontSizeOption);
