    async (pluginId: string, enabled: boolean) => {
      if (!manageCenterAppLayerConfig) {
        setStatus("App-layer settings are not loaded");
        return;
      }
      const existing = manageCenterAppLayerConfig.pluginPreferences.find((entry) => entry.pluginId === pluginId);
      const nextPreferences = existing
        ? manageCenterAppLayerConfig.pluginPreferences.map((entry) =>
            entry.pluginId === pluginId ? { ...entry, enabled } : entry
          )
        : [...manageCenterAppLayerConfig.pluginPreferences, { pluginId, enabled }];
      const nextConfig: AppLayerWorkspaceConfigPayload = {
        ...manageCenterAppLayerConfig,
        pluginPreferences: nextPreferences
      };
      try {
        if (enabled) {
          await runtimePluginManager.activatePlugin(pluginId);
        } else {
          await runtimePluginManager.deactivatePlugin(pluginId);
        }
      } catch (error) {
        const message = error instanceof Error ? error.message : "Plugin toggle failed";
        setStatus(`Plugin runtime toggle warning: ${message}`);
      }
      setPluginManagerStateVersion((previous) => previous + 1);
      await saveManageCenterConfig(
        nextConfig,
        `${enabled ? "Enabled" : "Disabled"} plugin preference for "${pluginId}"`
      );
    },
    [manageCenterAppLayerConfig, runtimePluginManager, saveManageCenterConfig]
